------------------------------------------------------------
----- ROOT ID FUNCTION FOR: RecordChange.RestoredFromID
------------------------------------------------------------
CREATE OR REPLACE FUNCTION __mj."fn_record_change_restored_from_id_get_root_id"(
    p_record_id uuid,
    p_parent_id uuid
) RETURNS uuid AS $$
    WITH RECURSIVE cte_root_parent AS (
        -- Anchor: Start from p_parent_id if not null, otherwise start from p_record_id
        SELECT
            "ID",
            "RestoredFromID",
            "ID" AS root_parent_id,
            0 AS depth
        FROM
            __mj."RecordChange"
        WHERE
            "ID" = COALESCE(p_parent_id, p_record_id)

        UNION ALL

        -- Recursive: Keep going up the hierarchy
        SELECT
            c."ID",
            c."RestoredFromID",
            c."ID" AS root_parent_id,
            p.depth + 1 AS depth
        FROM
            __mj."RecordChange" c
        INNER JOIN
            cte_root_parent p ON c."ID" = p."RestoredFromID"
        WHERE
            p.depth < 100  -- Prevent infinite loops
    )
    SELECT root_parent_id
    FROM cte_root_parent
    WHERE "RestoredFromID" IS NULL
    ORDER BY root_parent_id
    LIMIT 1;
$$ LANGUAGE sql STABLE;

