CREATE OR REPLACE FUNCTION __mj."fn_tag_merged_into_tag_id_get_root_id"(
    p_record_id uuid,
    p_parent_id uuid
) RETURNS uuid AS $$
    WITH RECURSIVE cte_root_parent AS (
        -- Anchor: Start from p_parent_id if not null, otherwise start from p_record_id
        SELECT
            "ID",
            "MergedIntoTagID",
            "ID" AS root_parent_id,
            0 AS depth
        FROM
            __mj."Tag"
        WHERE
            "ID" = COALESCE(p_parent_id, p_record_id)

        UNION ALL

        -- Recursive: Keep going up the hierarchy
        SELECT
            c."ID",
            c."MergedIntoTagID",
            c."ID" AS root_parent_id,
            p.depth + 1 AS depth
        FROM
            __mj."Tag" c
        INNER JOIN
            cte_root_parent p ON c."ID" = p."MergedIntoTagID"
        WHERE
            p.depth < 100  -- Prevent infinite loops
    )
    SELECT root_parent_id
    FROM cte_root_parent
    WHERE "MergedIntoTagID" IS NULL
    ORDER BY root_parent_id
    LIMIT 1;
$$ LANGUAGE sql STABLE;

