-- ============================================================
-- PostgreSQL Generated SQL for Entity: MJ: Version Labels
-- Item: fnVersionLabelParentID_GetRootID
-- Generated at: 2026-05-04T19:23:04.062Z
-- ============================================================

------------------------------------------------------------
----- ROOT ID FUNCTION FOR: VersionLabel.ParentID
------------------------------------------------------------
CREATE OR REPLACE FUNCTION __mj."fn_version_label_parent_id_get_root_id"(
    p_record_id uuid,
    p_parent_id uuid
) RETURNS uuid AS $$
    WITH RECURSIVE cte_root_parent AS (
        -- Anchor: Start from p_parent_id if not null, otherwise start from p_record_id
        SELECT
            "ID",
            "ParentID",
            "ID" AS root_parent_id,
            0 AS depth
        FROM
            __mj."VersionLabel"
        WHERE
            "ID" = COALESCE(p_parent_id, p_record_id)

        UNION ALL

        -- Recursive: Keep going up the hierarchy
        SELECT
            c."ID",
            c."ParentID",
            c."ID" AS root_parent_id,
            p.depth + 1 AS depth
        FROM
            __mj."VersionLabel" c
        INNER JOIN
            cte_root_parent p ON c."ID" = p."ParentID"
        WHERE
            p.depth < 100  -- Prevent infinite loops
    )
    SELECT root_parent_id
    FROM cte_root_parent
    WHERE "ParentID" IS NULL
    ORDER BY root_parent_id
    LIMIT 1;
$$ LANGUAGE sql STABLE;

